	if url, OK := isTheme(configFile); OK {
		return url
	}

	if strings.HasPrefix(configFile, "https://") {
		return configFile
	}

	configFile = path.ReplaceTildePrefixWithHomeDir(configFile)

	if filepath.IsAbs(configFile) {
		return configFile
	}

	return filepath.Join(parentFolder, configFile)
}

